// frontend/src/pages/AdminDashboard.tsx
import React, { useEffect, useState } from 'react';
import { adminService, bookService } from '../services/api';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Book, RevenueData } from '../types';
import BookCard from '../components/BookCard';

const AdminDashboard = () => {
  const [books, setBooks] = useState<Book[]>([]);
  const [reports, setReports] = useState<RevenueData[]>([]);

  const [newBook, setNewBook] = useState({ 
    title: '', 
    author: '', 
    price: 0, 
    coverImage: '' 
  });

  const loadAllData = async () => {
    try {
      const [booksRes, reportsRes] = await Promise.all([
        bookService.getAll(),
        adminService.getMonthlyReports()
      ]);
      setBooks(booksRes.data);
      setReports(reportsRes.data);
    } catch (error) {
      console.error("Veri yükleme hatası:", error);
    }
  };

  const handleReset = async () => {
    if (window.confirm("Sistemi temizleyip Golden State (Satışa Hazır) durumuna döndürmek istiyor musunuz?")) {
      await adminService.resetSystem();
      alert("Sistem başarıyla sıfırlandı ve demo verileri yüklendi!");
      loadAllData();
    }
  };

  const handleBulkSeed = async () => {
    if (window.confirm("Sisteme 100 adet rastgele kitap eklenecek. Onaylıyor musunuz?")) {
      try {
        await adminService.seedBulkData();
        alert("100 kitap başarıyla oluşturuldu!");
        loadAllData();
      } catch (error) {
        alert("Toplu kitap ekleme sırasında bir hata oluştu.");
      }
    }
  };

  const handleAddBook = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newBook.title || !newBook.author || newBook.price <= 0) {
      alert("Lütfen tüm alanları geçerli şekilde doldurun!");
      return;
    }

    try {
      await bookService.create(newBook);
      setNewBook({ title: '', author: '', price: 0, coverImage: '' }); 
      alert("Kitap başarıyla eklendi!");
      loadAllData(); 
    } catch (error) {
      alert("Kitap eklenirken bir hata oluştu.");
    }
  };

  useEffect(() => { loadAllData(); }, []);

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-8">
      {/* Header Bölümü */}
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h2 className="text-3xl font-extrabold text-gray-800 tracking-tight">Yönetici Dashboard</h2>

        <div className="flex flex-wrap justify-center gap-3">
          <button 
            onClick={handleBulkSeed} 
            className="px-5 py-2.5 bg-amber-500 hover:bg-amber-600 text-white font-bold rounded-lg shadow-md transition-all active:scale-95"
          >
            100 Rastgele Kitap Üret
          </button>

          <button 
            onClick={handleReset} 
            className="px-5 py-2.5 bg-red-600 hover:bg-red-700 text-white font-bold rounded-lg shadow-md transition-all active:scale-95"
          >
            Admin Reset (Golden State)
          </button>
        </div>
      </div>

      {/* Satış Grafiği Bölümü */}
      <section className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <h3 className="text-xl font-bold text-gray-700 mb-6">Aylık Satış Raporu (Revenue)</h3>
        <div className="w-full h-80">
          <ResponsiveContainer>
            <LineChart data={reports}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
              <XAxis dataKey="month" stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
              <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} axisLine={false} />
              <Tooltip 
                contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }}
              />
              <Line 
                type="monotone" 
                dataKey="revenue" 
                stroke="#3b82f6" 
                strokeWidth={4} 
                dot={{ r: 6, fill: '#3b82f6', strokeWidth: 2, stroke: '#fff' }} 
                activeDot={{ r: 8, strokeWidth: 0 }} 
              />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </section>

      {/* Yeni Kitap Ekleme Formu */}
      <section className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <h3 className="text-xl font-bold text-gray-700 mb-4">Yeni Kitap Ekle</h3>
        <form onSubmit={handleAddBook} className="flex flex-wrap gap-4 items-end">
          <div className="flex-1 min-w-[200px] space-y-1.5">
            <label className="text-xs font-semibold text-gray-500 uppercase ml-1">Kitap Adı</label>
            <input 
              type="text" 
              value={newBook.title}
              onChange={e => setNewBook({...newBook, title: e.target.value})}
              className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
              placeholder="Örn: Nutuk"
            />
          </div>
          <div className="flex-1 min-w-[200px] space-y-1.5">
            <label className="text-xs font-semibold text-gray-500 uppercase ml-1">Yazar</label>
            <input 
              type="text" 
              value={newBook.author}
              onChange={e => setNewBook({...newBook, author: e.target.value})}
              className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
              placeholder="Örn: M. Kemal Atatürk"
            />
          </div>

          <div className="flex-[1.5] min-w-[250px] space-y-1.5">
            <label className="text-xs font-semibold text-gray-500 uppercase ml-1">Kapak Fotoğrafı URL</label>
            <input 
              type="text" 
              value={newBook.coverImage}
              onChange={e => setNewBook({...newBook, coverImage: e.target.value})}
              className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
              placeholder="https://resim-linki.com/kapak.jpg"
            />
          </div>

          <div className="w-24 space-y-1.5">
            <label className="text-xs font-semibold text-gray-500 uppercase ml-1">Fiyat</label>
            <input 
              type="number" 
              value={newBook.price || ''}
              onChange={e => setNewBook({...newBook, price: Number(e.target.value)})}
              className="w-full px-4 py-2 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
              placeholder="0"
            />
          </div>
          <button 
            type="submit" 
            className="px-8 py-2.5 bg-emerald-500 hover:bg-emerald-600 text-white font-bold rounded-xl shadow-lg shadow-emerald-200 transition-all active:scale-95 h-[42px]"
          >
            Ekle
          </button>
        </form>
      </section>

      {/* Envanter Listesi */}
      <div className="space-y-4">
        <h3 className="text-2xl font-bold text-gray-800 ml-1">Envanter Yönetimi</h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {books.map(book => (
            <BookCard 
              key={book.id} 
              book={book} 
              actionButton={
                <button 
                  onClick={async () => { if(window.confirm("Silinsin mi?")) { await bookService.delete(book.id); loadAllData(); } }}
                  className="mt-4 w-full py-2 bg-slate-100 hover:bg-red-50 hover:text-red-600 text-slate-500 font-semibold rounded-lg transition-colors border border-transparent hover:border-red-100"
                >
                  Sistemden Kaldır
                </button>
              }
            />
          ))}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
